import { useEffect, useState } from "react";
import "./LeaveAdmin.css";

function LeaveAdmin() {
  const [requests, setRequests] = useState([]);

  useEffect(() => {
    const leaves = JSON.parse(localStorage.getItem("leaveRequests")) || [];
    setRequests(leaves);
  }, []);

  const handleStatusChange = (id, newStatus) => {
    const updated = requests.map((req) =>
      req.id === id ? { ...req, status: newStatus } : req
    );

    setRequests(updated);
    localStorage.setItem("leaveRequests", JSON.stringify(updated));

    alert("Leave Status Updated");
  };

  return (
    <div className="leave-admin-page">

      <h2>Leave Requests</h2>

      {/* ================= CURRENT LEAVE REQUESTS TABLE ================= */}
      {requests.length === 0 ? (
        <p className="no-requests">No Leave Requests Found</p>
      ) : (
        <table className="leave-table">
          <thead>
            <tr>
              <th>Employee</th>
              <th>Type</th>
              <th>From</th>
              <th>To</th>
              <th>Reason</th>
              <th>Applied</th>
              <th>Status</th>
            </tr>
          </thead>

          <tbody>
            {requests.map((req) => (
              <tr key={req.id}>
                <td>{req.empName}</td>
                <td>{req.leaveType}</td>
                <td>{req.fromDate}</td>
                <td>{req.toDate}</td>
                <td>{req.reason}</td>
                <td>{req.appliedDate}</td>

                <td>
                  <select
                    value={req.status}
                    onChange={(e) => handleStatusChange(req.id, e.target.value)}
                  >
                    <option value="Pending">Pending</option>
                    <option value="Approved">Approved</option>
                    <option value="Rejected">Rejected</option>
                  </select>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* ================= ALL EMPLOYEE LEAVE HISTORY ================= */}
      <h2 style={{ marginTop: "40px" }}>All Employees Leave History</h2>

      {requests.length === 0 ? (
        <p className="no-requests">No Leave History Found</p>
      ) : (
        <table className="leave-table">
          <thead>
            <tr>
              <th>Employee</th>
              <th>Type</th>
              <th>From</th>
              <th>To</th>
              <th>Reason</th>
              <th>Applied</th>
              <th>Status</th>
            </tr>
          </thead>

          <tbody>
            {requests.map((req) => (
              <tr key={req.id}>
                <td>{req.empName}</td>
                <td>{req.leaveType}</td>
                <td>{req.fromDate}</td>
                <td>{req.toDate}</td>
                <td>{req.reason}</td>
                <td>{req.appliedDate}</td>

                <td
                  style={{
                    color:
                      req.status === "Approved"
                        ? "green"
                        : req.status === "Rejected"
                        ? "red"
                        : "#ff9800",
                    fontWeight: "bold",
                  }}
                >
                  {req.status}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

    </div>
  );
}

export default LeaveAdmin;
